-- Canonical RC car-type taxonomy (discipline → groups → leaf).
-- Replaces the 12-node seed from 20260409120000; migrates user_car_taxonomy_rules to new leaf IDs.

-- Avoid slug unique collisions with legacy rows during insert
UPDATE "car_taxonomy_nodes" SET "slug" = "slug" || '-legacy' WHERE "id" LIKE 'c1000000-%';

-- New node IDs: c2000000-0000-4000-8000-000000000001 .. 000000000041


-- Point existing rules at new leaf IDs (semantic mapping from old 12-node seed)
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000018'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-000000000003';
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000019'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-000000000004';
