  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-000000000006';
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000014'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-000000000007';
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000032'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-000000000009';
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000034'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-00000000000a';
UPDATE "user_car_taxonomy_rules" SET "taxonomy_node_id" = 'c2000000-0000-4000-8000-000000000016'
  WHERE "taxonomy_node_id" = 'c1000000-0000-4000-8000-00000000000c';

-- Remove legacy seed nodes (children before parents; leaves first)
DELETE FROM "car_taxonomy_nodes" WHERE "id" IN (
  'c1000000-0000-4000-8000-000000000003',
  'c1000000-0000-4000-8000-000000000004',
  'c1000000-0000-4000-8000-000000000006',
  'c1000000-0000-4000-8000-000000000007',
  'c1000000-0000-4000-8000-000000000009',
  'c1000000-0000-4000-8000-00000000000a',
  'c1000000-0000-4000-8000-00000000000c'
);
